const ProfileScreen = ({ user, cartItems }) => {
  return (
    <section className="profile-grid">
      <div className="panel">
        <h1>Moj profil</h1>
        <p>{user.name}</p>
        <p>{user.email}</p>
      </div>
      <div className="panel">
        <h2>Moje razmene</h2>
        {cartItems.length === 0 ? (
          <p>Nema aktivnih zahteva.</p>
        ) : (
          cartItems.map((item) => <p key={item.id}>{item.name} - zahtev u pripremi</p>)
        )}
      </div>
    </section>
  );
};

export default ProfileScreen;
